export interface ReliabilityScore {
  score: number;
  breakdown: {
    passRateContribution: number;
    flakinessContribution: number;
    stabilityContribution: number;
  };
  rawMetrics: {
    passRate: number;
    flakyRate: number;
    durationCV: number; // coefficient of variation
  };
  trend: number; // change from previous period (-100 to +100)
  status: 'healthy' | 'warning' | 'critical';
}

export async function getReliabilityScore(
  organizationId: string,
  dateRange?: { from?: string; to?: string }
): Promise<ReliabilityScore> {
  const dateFilter = dateRange?.from && dateRange?.to
    ? sql`AND te.started_at BETWEEN ${dateRange.from}::timestamptz AND ${dateRange.to}::timestamptz`
    : sql`AND te.started_at > NOW() - INTERVAL '7 days'`;

  const result = await sql`
    WITH current_metrics AS (
      SELECT
        COUNT(*) FILTER (WHERE tr.status = 'passed')::float / NULLIF(COUNT(*), 0) * 100 as pass_rate,
        COUNT(*) FILTER (WHERE tr.is_flaky = true)::float / NULLIF(COUNT(*), 0) * 100 as flaky_rate,
        COALESCE(STDDEV(tr.duration_ms) / NULLIF(AVG(tr.duration_ms), 0), 0) as duration_cv
      FROM test_results tr
      JOIN test_executions te ON tr.execution_id = te.id
      WHERE te.organization_id = ${organizationId}
        ${dateFilter}
    ),
    previous_metrics AS (
      SELECT
        COUNT(*) FILTER (WHERE tr.status = 'passed')::float / NULLIF(COUNT(*), 0) * 100 as pass_rate,
        COUNT(*) FILTER (WHERE tr.is_flaky = true)::float / NULLIF(COUNT(*), 0) * 100 as flaky_rate,
        COALESCE(STDDEV(tr.duration_ms) / NULLIF(AVG(tr.duration_ms), 0), 0) as duration_cv
      FROM test_results tr
      JOIN test_executions te ON tr.execution_id = te.id
      WHERE te.organization_id = ${organizationId}
        AND te.started_at BETWEEN NOW() - INTERVAL '14 days' AND NOW() - INTERVAL '7 days'
    )
    SELECT
      cm.pass_rate,
      cm.flaky_rate,
      cm.duration_cv,
      pm.pass_rate as prev_pass_rate,
      pm.flaky_rate as prev_flaky_rate,
      pm.duration_cv as prev_duration_cv
    FROM current_metrics cm
    CROSS JOIN previous_metrics pm
  `;

  const row = result[0] || { pass_rate: 0, flaky_rate: 0, duration_cv: 0 };

  const passRateContribution = (row.pass_rate || 0) * 0.4;
  const flakinessContribution = ((100 - (row.flaky_rate || 0)) * 0.3);
  const stabilityContribution = ((1 - Math.min(row.duration_cv || 0, 1)) * 100 * 0.3);

  const score = Math.round(passRateContribution + flakinessContribution + stabilityContribution);

  // Calculate previous score for trend
  const prevScore = row.prev_pass_rate
    ? Math.round(
        (row.prev_pass_rate * 0.4) +
        ((100 - row.prev_flaky_rate) * 0.3) +
        ((1 - Math.min(row.prev_duration_cv, 1)) * 100 * 0.3)
      )
    : score;

  return {
    score,
    breakdown: {
      passRateContribution: Math.round(passRateContribution),
      flakinessContribution: Math.round(flakinessContribution),
      stabilityContribution: Math.round(stabilityContribution),
    },
    rawMetrics: {
      passRate: Math.round(row.pass_rate || 0),
      flakyRate: Math.round(row.flaky_rate || 0),
      durationCV: Math.round((row.duration_cv || 0) * 100) / 100,
    },
    trend: score - prevScore,
    status: score >= 80 ? 'healthy' : score >= 60 ? 'warning' : 'critical',
  };
}

import { NextResponse } from "next/server";
import { getSessionContext } from "@/lib/session-context";
import { getReliabilityScore } from "@/lib/db";

export const dynamic = "force-dynamic";

export async function GET(request: Request) {
  try {
    const context = await getSessionContext();
    if (!context) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { searchParams } = new URL(request.url);
    const from = searchParams.get("from") || undefined;
    const to = searchParams.get("to") || undefined;

    const dateRange = from && to ? { from, to } : undefined;
    const score = await getReliabilityScore(context.organizationId, dateRange);

    return NextResponse.json(score);
  } catch (error) {
    console.error("[API] Error fetching reliability score:", error);
    return NextResponse.json(
      { error: "Failed to fetch reliability score" },
      { status: 500 }
    );
  }
}

"use client";

import { useState, useEffect } from "react";
import { RadialBarChart, RadialBar, PolarAngleAxis, ResponsiveContainer } from "recharts";
import { Activity, TrendingUp, TrendingDown, Minus } from "lucide-react";
import type { ReliabilityScore } from "@/lib/types";

export function ReliabilityScoreCard() {
  const [score, setScore] = useState<ReliabilityScore | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetch("/api/reliability-score")
      .then((res) => res.json())
      .then((data) => {
        if (data.error) throw new Error(data.error);
        setScore(data);
      })
      .catch((err) => setError(err.message))
      .finally(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <div className="glass-card glass-card-glow p-6">
        <div className="flex items-center gap-2 mb-4">
          <Activity className="w-5 h-5 text-[oklch(0.75_0.15_195)]" />
          <h3 className="font-semibold">Reliability Score</h3>
        </div>
        <div className="h-48 flex items-center justify-center">
          <div className="animate-pulse bg-muted/30 w-32 h-32 rounded-full" />
        </div>
      </div>
    );
  }

  if (error || !score) {
    return (
      <div className="glass-card glass-card-glow p-6">
        <div className="flex items-center gap-2 mb-4">
          <Activity className="w-5 h-5 text-[oklch(0.75_0.15_195)]" />
          <h3 className="font-semibold">Reliability Score</h3>
        </div>
        <p className="text-sm text-muted-foreground">{error || "No data available"}</p>
      </div>
    );
  }

  const getScoreColor = (status: string) => {
    switch (status) {
      case "healthy": return "oklch(0.75 0.18 145)"; // green
      case "warning": return "oklch(0.75 0.15 85)";  // yellow
      case "critical": return "oklch(0.65 0.2 25)";  // red
      default: return "oklch(0.75 0.15 195)";        // cyan
    }
  };

  const TrendIcon = score.trend > 0 ? TrendingUp : score.trend < 0 ? TrendingDown : Minus;
  const trendColor = score.trend > 0 ? "text-green-500" : score.trend < 0 ? "text-red-500" : "text-muted-foreground";

  const chartData = [{ value: score.score, fill: getScoreColor(score.status) }];

  return (
    <div className="glass-card glass-card-glow p-6">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <Activity className="w-5 h-5 text-[oklch(0.75_0.15_195)]" />
          <h3 className="font-semibold">Reliability Score</h3>
        </div>
        <div className={`flex items-center gap-1 text-sm ${trendColor}`}>
          <TrendIcon className="w-4 h-4" />
          <span>{score.trend > 0 ? "+" : ""}{score.trend}</span>
        </div>
      </div>

      <div className="h-48 relative">
        <ResponsiveContainer width="100%" height="100%">
          <RadialBarChart
            cx="50%"
            cy="50%"
            innerRadius="60%"
            outerRadius="90%"
            startAngle={180}
            endAngle={0}
            data={chartData}
          >
            <PolarAngleAxis type="number" domain={[0, 100]} angleAxisId={0} tick={false} />
            <RadialBar
              background={{ fill: "oklch(1 0 0 / 0.05)" }}
              dataKey="value"
              cornerRadius={10}
              angleAxisId={0}
            />
          </RadialBarChart>
        </ResponsiveContainer>
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <span className="text-4xl font-bold" style={{ color: getScoreColor(score.status) }}>
            {score.score}
          </span>
          <span className="text-sm text-muted-foreground capitalize">{score.status}</span>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-2 mt-4 text-center">
        <div>
          <p className="text-xs text-muted-foreground">Pass Rate</p>
          <p className="text-sm font-medium">{score.rawMetrics.passRate}%</p>
        </div>
        <div>
          <p className="text-xs text-muted-foreground">Flaky Rate</p>
          <p className="text-sm font-medium">{score.rawMetrics.flakyRate}%</p>
        </div>
        <div>
          <p className="text-xs text-muted-foreground">Stability</p>
          <p className="text-sm font-medium">{Math.round((1 - score.rawMetrics.durationCV) * 100)}%</p>
        </div>
      </div>
    </div>
  );
}

